import React, { useState } from 'react';
import axios from 'axios';
import { Save, Trash2, Loader2, FileSpreadsheet } from 'lucide-react';

const GestionInventario = ({ localId, onComplete }) => {
    // Iniciamos con 10 filas vacías
    const crearFilasVacias = (cant) => Array(cant).fill().map(() => ({
        tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: ''
    }));

    const [filas, setFilas] = useState(crearFilasVacias(10));
    const [loading, setLoading] = useState(false);

    const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

    // FUNCIÓN MÁGICA: Maneja el pegado desde Excel
    const handlePaste = (e, filaIndex, colIndex) => {
        const pasteData = e.clipboardData.getData('text');
        const rows = pasteData.split(/\r\n|\n|\r/); // Divide por filas
        
        const nuevasFilas = [...filas];

        rows.forEach((rowText, i) => {
            if (!rowText) return;
            const targetFilaIndex = filaIndex + i;
            
            // Si el pegado excede las filas actuales, creamos una nueva
            if (!nuevasFilas[targetFilaIndex]) {
                nuevasFilas[targetFilaIndex] = { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' };
            }

            const cells = rowText.split('\t'); // Excel separa columnas con Tabs
            cells.forEach((cellText, j) => {
                const targetColIndex = colIndex + j;
                const fieldNames = ['tipo', 'marca', 'contenido', 'categoria', 'precioNuevo', 'precioViejo', 'stock'];
                const fieldName = fieldNames[targetColIndex];

                if (fieldName) {
                    nuevasFilas[targetFilaIndex][fieldName] = cellText.trim();
                }
            });
        });

        setFilas(nuevasFilas);
        e.preventDefault(); // Evita que se pegue el texto plano en una sola celda
    };

    const handleInputChange = (index, field, value) => {
        const nuevas = [...filas];
        nuevas[index][field] = value;
        setFilas(nuevas);
    };

    const handleGuardar = async () => {
        const validos = filas.filter(f => f.tipo && f.marca && f.precioNuevo);
        if (validos.length === 0) return alert("No hay datos válidos para cargar.");

        setLoading(true);
        try {
            await axios.post(`${API_URL}/api/ofertas/bulk`, {
                localId,
                productos: validos.map(p => ({
                    ...p,
                    producto: `${p.tipo} ${p.marca} ${p.contenido}`.trim(),
                    precioNuevo: Number(p.precioNuevo),
                    precioViejo: Number(p.precioViejo) || Number(p.precioNuevo),
                    stock: Number(p.stock) || 0
                }))
            });
            alert("¡Carga masiva exitosa!");
            setFilas(crearFilasVacias(10));
            onComplete();
        } catch (err) {
            alert("Error: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={container}>
            <div style={header}>
                <FileSpreadsheet size={20} color="#107c41" />
                <h3 style={{margin:0}}>Carga Tipo Excel</h3>
                <span style={tip}>Tip: Parate en la primera celda y pegá (Ctrl+V)</span>
            </div>

            <div style={tableWrapper}>
                <table style={table}>
                    <thead>
                        <tr style={thr}>
                            <th style={th}>Tipo</th>
                            <th style={th}>Marca</th>
                            <th style={th}>Contenido</th>
                            <th style={th}>Categoría</th>
                            <th style={th}>$ Oferta</th>
                            <th style={th}>$ Viejo</th>
                            <th style={th}>Stock</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filas.map((f, i) => (
                            <tr key={i}>
                                {['tipo', 'marca', 'contenido', 'categoria', 'precioNuevo', 'precioViejo', 'stock'].map((field, j) => (
                                    <td key={j} style={td}>
                                        <input
                                            style={input}
                                            value={f[field]}
                                            onChange={(e) => handleInputChange(i, field, e.target.value)}
                                            onPaste={(e) => handlePaste(e, i, j)}
                                            placeholder="..."
                                        />
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <div style={footer}>
                <button onClick={() => setFilas(crearFilasVacias(10))} style={btnSec}>Limpiar Grilla</button>
                <button onClick={handleGuardar} style={btnPri} disabled={loading}>
                    {loading ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>}
                    Guardar todo el Inventario
                </button>
            </div>
        </div>
    );
};

// --- ESTILOS ---
const container = { background: '#fff', borderRadius: '8px', border: '1px solid #ddd', marginBottom: '20px', overflow: 'hidden' };
const header = { padding: '15px', background: '#f8fafc', borderBottom: '1px solid #ddd', display: 'flex', alignItems: 'center', gap: '10px' };
const tip = { fontSize: '0.75rem', color: '#64748b', marginLeft: 'auto' };
const tableWrapper = { overflowX: 'auto', maxHeight: '400px' };
const table = { width: '100%', borderCollapse: 'collapse' };
const th = { padding: '10px', background: '#f1f5f9', border: '1px solid #ddd', fontSize: '0.8rem', textAlign: 'left' };
const td = { border: '1px solid #ddd', padding: 0 };
const input = { width: '100%', padding: '10px', border: 'none', outline: 'none', fontSize: '0.85rem' };
const footer = { padding: '15px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const btnPri = { background: '#107c41', color: '#fff', border: 'none', padding: '10px 20px', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', gap: '8px' };
const btnSec = { background: '#fff', border: '1px solid #ddd', padding: '10px 15px', borderRadius: '6px', cursor: 'pointer' };

export default GestionInventario;
